window.PLANTUML_STDLIB.awslib10.awscommon=';!define AWS_COLOR #232F3E;!define AWS_BG_COLOR #FFFFFF;!define AWS_BORDER_COLOR #FF9900;!define AWS_SYMBOL_COLOR AWS_COLOR;;;!define TECHN_FONT_SIZE 12;;skinparam defaultTextAlignment center;;skinparam wrapWidth 200;skinparam maxMessageSize 150;;skinparam rectangle {;    StereotypeFontSize 12;};;skinparam Arrow {;    Color #666666;    FontColor #666666;    FontSize 12;};;!definelong AWSEntityColoring(stereo);skinparam rectangle<<stereo>> {;    BackgroundColor AWS_BG_COLOR;    BorderColor AWS_BORDER_COLOR;};skinparam participant<<stereo>> {;    BackgroundColor AWS_BG_COLOR;    BorderColor AWS_BORDER_COLOR;};!enddefinelong;;;!definelong LAYOUT_AS_SKETCH;skinparam backgroundColor #EEEBDC;skinparam handwritten true;skinparam defaultFontName "Comic Sans MS";center footer <font color=red>Warning:</font> Created for discussion, needs to be validated;!enddefinelong;;!define LAYOUT_TOP_DOWN top to bottom direction;!define LAYOUT_LEFT_RIGHT left to right direction;;;!definelong AWSEntity(e_alias, e_label, e_techn, e_color, e_sprite, e_stereo);rectangle "==e_label\\n<color:e_color><$e_sprite></color>\\n//<size:TECHN_FONT_SIZE>[e_techn]</size>//" <<e_stereo>> as e_alias;!enddefinelong;;!definelong AWSEntity(e_alias, e_label, e_techn, e_descr, e_color, e_sprite, e_stereo);rectangle "==e_label\\n<color:e_color><$e_sprite></color>\\n//<size:TECHN_FONT_SIZE>[e_techn]</size>//\\n\\n e_descr" <<e_stereo>> as e_alias;!enddefinelong;;!definelong AWSParticipant(p_alias, p_label, p_techn, p_color, p_sprite, p_stereo);participant "p_label\\n<size:TECHN_FONT_SIZE>[p_techn]</size>" as p_alias << ($p_sprite, p_color) p_stereo>>;!enddefinelong;;!definelong AWSParticipant(p_alias, p_label, p_techn, p_descr, p_color, p_sprite, p_stereo);participant "p_label\\n<size:TECHN_FONT_SIZE>[p_techn]</size>\\n\\n p_descr" as p_alias << ($p_sprite, p_color) p_stereo>>;!enddefinelong'.split(";");
